module serial2parallel
(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output dout_parallel,
    output reg dout_valid
);
    reg [3:0] cnt;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 4'd0;
            dout_valid <= 1'b0;
        end
        else if (cnt == 4'd8) begin
            cnt <= 4'd0;
            dout_valid <= 1'b1;
        end
        else begin
            cnt <= cnt + 1'b1;
            dout_valid <= 1'b0;
        end
    end
    always @(posedge clk) begin
        if (cnt == 4'd0) dout_parallel <= 8'd0;
        else if (cnt <= 4'd8) dout_parallel <= {dout_parallel[6:0], din_serial};
    end
endmodule
